import React, { useContext } from 'react'
import { Cards } from '../components/data/Cards';
import { UserContext } from "../components/User"
import { Link } from 'react-router-dom';

function Korzina() {
    const User = useContext(UserContext);
    const handleKorzinaDelete = (id) => {
        User.setUser({
            ...User.user,
             korzina: User.user.korzina.filter((el) => el !== id),
        });
    };
    return (
        <div className="Korzina">
            {User && User.user && User.user.korzina.length > 0 ? (
                User.user.korzina.map((el) => {
                const product = Cards.filter((prod) => String(prod.id) === String(el))[0];
                return (
                    <div className="Korzina__card">
                        <div className="Kor__cards">
                       <Link to={"p/" + product.id }><h1>{product.title}</h1> </Link> 
                        <p>{product.cost}</p>
                        </div>
                        <div className="img">  <img src={product.img} alt={product.title} /></div>
                        <button className="Korzina__delete" onClick={() => handleKorzinaDelete(product.id)}>Удалить из избранного</button>
                    </div>
                );
            })
            ) : (
                <h1>Ваша избранные пуста!</h1>
            )}
        </div>
    );
}

export default Korzina;
